{%- comment -%} ---------------- THE EDITOR ------------------ {%- endcomment -%}

{%- if request.design_mode -%}
<script>
  (function FAQThemeEditor(SectionsDesign) {
    'use strict';

    document.addEventListener('shopify:section:load', sectionLoad);
    document.addEventListener('shopify:block:select', blockToggle);
    document.addEventListener('shopify:block:deselect', blockToggle);

    function sectionLoad(evt) {
      var sectionId = evt.detail.sectionId;
      var section =  SectionsDesign.faq[sectionId];

      if (!section) return;
      SectionsDesign.faq[sectionId] = section.init(sectionId);     
    }

    function blockToggle(evt) {
      var section = SectionsDesign.faq[evt.detail.sectionId];
      if (!section) return;

      var block = section.blocks[evt.detail.blockId];
      if (!block) return;

      evt.type === 'shopify:block:select' ? block.select() : block.deselect();
    }

  })(window.SectionsDesign = window.SectionsDesign || {});
</script>
{%- endif -%}

{% paginate search.results by 24 %}
  {% for product in search.results %}
    {% comment %}
      Every product is in multiple auto collections that look like this: ["building consumables", "building consumables > solder & flux", "building consumables > solder & flux > rosin flux"]
      So we search for the _longest handle_ to find the leaf category of the product and link to that.
    {% endcomment %}
    {% assign collection_with_longest_handle = product.collections | sort: 'handle.size' | last %}
    {% assign modified_handle = collection_with_longest_handle.handle | remove_first: 'hardware-' %}
    <div>
      <img src="{{ product.featured_image | image_url }}" height="100px" alt="{{ product.title }}">
      <a href="/pages/category/{{ modified_handle }}#{{ product.handle }}">
        {{ product.title }}
      </a>
    </div>
  {% endfor %}
{% endpaginate %}

